const body = $input.item.json;

// Handle GitHub webhook payload
const event = $input.item.headers['x-github-event'];

let message = '';
let color = 3447003;

if (event === 'issues') {
  const issue = body.issue;
  const action = body.action;

  if (action === 'opened') {
    message = `🆕 *New Issue Opened*\n\n*#${issue.number}:* ${issue.title}\n\n${issue.body?.substring(0, 200) || 'No description'}\n\n👤 ${issue.user.login}\n🔗 ${issue.html_url}`;
    color = 5763719;
  } else if (action === 'closed') {
    message = `✅ *Issue Closed*\n\n*#${issue.number}:* ${issue.title}\n\n👤 ${issue.user.login}\n🔗 ${issue.html_url}`;
    color = 2961146;
  } else if (action === 'assigned') {
    message = `👤 *Issue Assigned*\n\n*#${issue.number}:* ${issue.title}\n\nAssigned to: @${body.assignee?.login}\n🔗 ${issue.html_url}`;
  }
} else if (event === 'pull_request') {
  const pr = body.pull_request;
  const action = body.action;

  if (action === 'opened') {
    message = `📝 *PR Opened*\n\n*#${pr.number}:* ${pr.title}\n\n👤 ${pr.user.login}\n🔗 ${pr.html_url}`;
    color = 1247808;
  } else if (action === 'merged') {
    message = `🎉 *PR Merged*\n\n*#${pr.number}:* ${pr.title}\n\n👤 ${pr.user.login}\n🔗 ${pr.html_url}`;
    color = 8383491;
  }
}

if (!message) {
  message = `📬 *GitHub Event:* ${event}\n\n${JSON.stringify(body, null, 2).substring(0, 500)}`;
}

return [{ json: { message, color } }];
